```hcl
# Assign the Global Administrator role to a specific principal (user or group)
# Critical: Looks up the built-in Global Administrator role
data "azuread_directory_role" "global_admin" {
  display_name = "Global Administrator"
}

# Critical: Creates the role assignment so the principal becomes a Global Administrator
# This helps reach the recommended 2-4 Global Administrators
resource "azuread_directory_role_assignment" "<example_resource_name>" {
  role_id             = data.azuread_directory_role.global_admin.object_id  # Critical: GA role ID
  principal_object_id = "<example_resource_id>"                             # Critical: target user/group object ID
}
```

```hcl
resource "azuread_conditional_access_policy" "<example_resource_name>" {
  display_name = "<example_resource_name>"
  state        = "enabled" # Critical: policy must be enabled to PASS

  conditions {
    users {
      include_users = ["All"] # Critical: include all users
      exclude_roles = ["62e90394-69f5-4237-9190-012177145e10"] # Critical: exclude admin role(s) so only admins can access
    }
    applications {
      included_applications = ["MicrosoftAdminPortals"] # Critical: target Microsoft Admin Portals
    }
  }

  grant_controls {
    built_in_controls = ["block"] # Critical: block non-excluded users
  }
}
```

```hcl
